return {
  json: {
    request_id: String($json.request_id).replace(/^=/, ''),
    workflow_type: $json.workflow_type,
    step_id: 'extract_text',
    status: 'skipped',
    error: `Unsupported document source: ${$json.params?.document_source || ''}`
  }
};

const ctx = $node["Extract context"].json;
const items = $input.all();

const requestId = String(ctx.request_id || "").replace(/^=/, "");
const workflowType = ctx.workflow_type || "hr_recruitment";
const ALLOWED_MIME_PREFIXES = [
  'application/pdf',
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  'application/octet-stream',
];
const ALLOWED_EXTENSIONS = ['.pdf', '.doc', '.docx'];
const FILENAME_HINT_RE = /(resume|cv|curriculum[ _-]?vitae|biodata|bio[ _-]?data|candidate|profile)/i;
const MESSAGE_HINT_RE = /(resume|cv|curriculum vitae|job application|application for|candidate profile|candidate resume)/i;
const SECTION_HINT_RE = /\b(summary|objective|experience|employment|work history|skills|technical skills|projects|education|certifications|achievements|internship|profile)\b/gi;
const NEGATIVE_HINT_RE = /(thank you for your interest|admission|brochure|newsletter|unsubscribe|prospectus|fee structure|campus|apply now)/i;
const EMAIL_RE = /[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i;
const PHONE_RE = /(?:\+?\d{1,3}[\s-]?)?(?:\(?\d{3,5}\)?[\s-]?)?\d{3,5}[\s-]?\d{3,5}/;
const PROFILE_RE = /(linkedin\.com|github\.com|portfolio|behance|leetcode)/i;
const AUTOMATED_SENDER_RE = /(no-?reply|mailer-daemon|notification|newsletter)/i;

function parseHeader(messageJson, headerName) {
  const headers = Array.isArray(messageJson?.payload?.headers) ? messageJson.payload.headers : [];
  const found = headers.find((h) => (h.name || '').toLowerCase() === headerName.toLowerCase());
  return (found && found.value) || '';
}

function parseSender(messageJson) {
  const fromCandidate = parseHeader(messageJson, 'From') || messageJson?.from || messageJson?.sender || messageJson?.email || '';

  let rawText = '';
  let email = '';
  let namePart = '';

  if (typeof fromCandidate === 'string') {
    rawText = fromCandidate.trim();
  } else if (fromCandidate && typeof fromCandidate === 'object') {
    rawText = String(fromCandidate.text || fromCandidate.value || fromCandidate.name || '').trim();
    email = String(fromCandidate.email || fromCandidate.address || fromCandidate.emailAddress || '').trim();
    namePart = String(fromCandidate.name || '').trim();
  }

  const emailMatch = rawText.match(/<([^>]+)>/) || rawText.match(EMAIL_RE);
  if (!email && emailMatch) {
    email = (emailMatch[1] || emailMatch[0] || '').trim();
  }

  if (!email) {
    const fallback = (JSON.stringify(messageJson || {}).match(EMAIL_RE) || [''])[0];
    email = String(fallback || '').trim();
  }

  if (!namePart) {
    namePart = rawText.replace(/<[^>]+>/, '').trim().replace(/^\"|\"$/g, '');
  }
  if (!namePart && email) {
    namePart = email.split('@')[0].replace(/[._-]+/g, ' ');
  }

  return {
    from_header: rawText || null,
    candidate_email: email || null,
    candidate_name: (namePart || 'Candidate')
      .split(' ')
      .filter(Boolean)
      .map((w) => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' '),
  };
}

function normalizeText(value) {
  return String(value || '').trim();
}

function hasAllowedAttachment(filename, mimeType) {
  const name = normalizeText(filename).toLowerCase();
  const mime = normalizeText(mimeType).toLowerCase();
  return ALLOWED_EXTENSIONS.some((ext) => name.endsWith(ext)) || ALLOWED_MIME_PREFIXES.some((prefix) => mime.startsWith(prefix));
}

function scoreResumeSignal({ subject, snippet, filename, text, senderEmail }) {
  const cleanSubject = normalizeText(subject);
  const cleanSnippet = normalizeText(snippet);
  const cleanFilename = normalizeText(filename);
  const cleanText = normalizeText(text);
  const combinedText = [cleanSubject, cleanSnippet, cleanText].filter(Boolean).join('\n');
  const sectionMatches = Array.from(new Set((combinedText.match(SECTION_HINT_RE) || []).map((m) => m.toLowerCase())));
  const wordCount = cleanText.split(/\s+/).filter(Boolean).length;
  const filenameHint = FILENAME_HINT_RE.test(cleanFilename);
  const messageHint = MESSAGE_HINT_RE.test([cleanSubject, cleanSnippet].join(' '));
  const hasEmail = EMAIL_RE.test(cleanText) || EMAIL_RE.test(cleanSnippet) || EMAIL_RE.test(cleanSubject);
  const hasPhone = PHONE_RE.test(cleanText);
  const hasProfile = PROFILE_RE.test(cleanText);
  const negativeHit = NEGATIVE_HINT_RE.test([cleanSubject, cleanSnippet, cleanText.slice(0, 400)].join(' '));
  const automatedSender = AUTOMATED_SENDER_RE.test(normalizeText(senderEmail));

  let score = 0;
  const reasons = [];
  if (filenameHint) {
    score += 4;
    reasons.push('attachment filename looks like a resume');
  }
  if (messageHint) {
    score += 2;
    reasons.push('subject/snippet references resume or application');
  }
  if (sectionMatches.length >= 2) {
    score += Math.min(4, sectionMatches.length);
    reasons.push(`resume sections found: ${sectionMatches.join(', ')}`);
  }
  if (wordCount >= 120) {
    score += 1;
    reasons.push(`document length ${wordCount} words`);
  }
  if (hasEmail) {
    score += 1;
    reasons.push('contact email found in content');
  }
  if (hasPhone) {
    score += 1;
    reasons.push('phone number found in content');
  }
  if (hasProfile) {
    score += 1;
    reasons.push('professional profile link found');
  }
  if (negativeHit) {
    score -= 4;
    reasons.push('negative non-resume phrase found');
  }
  if (automatedSender) {
    score -= 1;
    reasons.push('automated sender pattern found');
  }

  const isResume = (score >= 6 && sectionMatches.length >= 2) || (filenameHint && score >= 5) || (sectionMatches.length >= 3 && hasEmail);
  return {
    isResume,
    score,
    reasons,
    sectionMatches,
    wordCount,
  };
}

const lines = [];
const candidates = [];
const filteredOut = [];

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  const m = item.json || {};
  const binary = item.binary || {};

  const subject = m.subject || parseHeader(m, 'Subject');
  const snippet = m.snippet || '';
  const sender = parseSender(m);
  const attachmentKeys = Object.keys(binary);
  const acceptedAttachments = [];
  const rejectedAttachments = [];

  for (const key of attachmentKeys) {
    const b = binary[key] || {};
    const filename = b.fileName || key;
    const mimeType = b.mimeType || 'application/octet-stream';

    if (!hasAllowedAttachment(filename, mimeType)) {
      rejectedAttachments.push({ filename, mimeType, reason: 'unsupported_attachment_type' });
      continue;
    }

    let contentBase64 = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(idx, key);
      contentBase64 = Buffer.from(buf).toString('base64');
    } catch (err) {
      contentBase64 = normalizeText(b.data || '');
    }

    if (!contentBase64) {
      rejectedAttachments.push({ filename, mimeType, reason: 'binary_buffer_unavailable' });
      continue;
    }

    try {
      const res = await this.helpers.httpRequest({
        method: 'POST',
        url: 'http://localhost:8000/api/document/extract',
        body: {
          request_id: requestId,
          workflow_type: workflowType,
          step_id: 'extract_text',
          filename,
          mime_type: mimeType,
          content_base64: contentBase64,
          language: 'eng',
          use_ocr_fallback: true,
        },
        json: true,
      });

      const extracted = normalizeText(res?.extracted_text || '');
      const verdict = scoreResumeSignal({
        subject,
        snippet,
        filename,
        text: extracted,
        senderEmail: sender.candidate_email,
      });

      if (!verdict.isResume) {
        rejectedAttachments.push({
          filename,
          mimeType,
          reason: 'not_resume_like',
          score: verdict.score,
          reasons: verdict.reasons,
          word_count: verdict.wordCount,
        });
        continue;
      }

      acceptedAttachments.push({
        filename,
        mimeType,
        text: extracted,
        score: verdict.score,
        reasons: verdict.reasons,
        word_count: verdict.wordCount,
      });
    } catch (err) {
      rejectedAttachments.push({ filename, mimeType, reason: 'document_extract_failed', error: String(err.message || err) });
    }
  }

  if (!acceptedAttachments.length) {
    filteredOut.push({
      message_id: m.id || null,
      subject: subject || null,
      sender: sender.from_header,
      candidate_email: sender.candidate_email,
      reason: 'no_resume_like_attachments',
      rejected_attachments: rejectedAttachments,
    });
    continue;
  }

  const attachmentTexts = acceptedAttachments.map((entry) => `[Attachment: ${entry.filename}]\n${entry.text}`);
  const resumeText = attachmentTexts.join('\n\n').trim();
  if (resumeText) {
    lines.push(resumeText);
  }

  candidates.push({
    candidate_name: sender.candidate_name || `Candidate ${idx + 1}`,
    candidate_email: sender.candidate_email,
    resume_text: resumeText,
    skills: [],
    experience_years: null,
    metadata: {
      source: 'gmail',
      message_id: m.id || null,
      subject: subject || null,
      from: sender.from_header,
      accepted_attachment_count: acceptedAttachments.length,
      accepted_attachments: acceptedAttachments.map((entry) => ({
        filename: entry.filename,
        mimeType: entry.mimeType,
        score: entry.score,
        reasons: entry.reasons,
      })),
      rejected_attachments: rejectedAttachments,
    },
  });
}

return [{
  json: {
    request_id: requestId,
    workflow_type: workflowType,
    step_id: 'extract_text',
    status: 'completed',
    source: 'email://inbox',
    engine: 'gmail+attachments+resume_filter',
    email_message_count: items.length,
    email_message_ids: items.map((i) => i.json?.id).filter(Boolean),
    candidate_count: candidates.length,
    filtered_out_count: filteredOut.length,
    filtered_out_messages: filteredOut,
    extracted_text: lines.join('\n\n'),
    candidates,
    error: null,
  },
}];

