const ctx = $node["Extract context"].json;
const shortlisted = Array.isArray($json.shortlisted) ? $json.shortlisted : [];

const audit = shortlisted.map((candidate) => ({
  candidate_name: candidate.candidate_name || candidate.name || null,
  candidate_email: candidate.candidate_email || candidate.email || null,
  score: candidate.score ?? null,
  interview_start: candidate.metadata?.interview_start || candidate.interview_start || null,
  interview_end: candidate.metadata?.interview_end || candidate.interview_end || null,
  shortlist_rank: candidate.metadata?.shortlist_rank || null,
  slot_audit: candidate.metadata?.slot_audit || null,
}));

return [{
  json: {
    request_id: String(ctx.request_id || "").replace(/^=/, ""),
    workflow_type: ctx.workflow_type || null,
    step_id: "shortlist",
    status: "completed",
    shortlisted_count: shortlisted.length,
    shortlisted: audit,
  }
