const ctx = $node["Extract context"].json || {};
const steps = Array.isArray(ctx.steps) ? ctx.steps : [];
const extractResult = $json || {};
const triggerContext = ctx.trigger_context || {};
const triggerCandidate = triggerContext.candidate || triggerContext.payload || {};

const rankStep = steps.find((s) => s.step_id === 'rank_candidates') || {};
const rankParams = rankStep.params || {};

const extractedCandidates = Array.isArray(extractResult.candidates) ? extractResult.candidates : [];
const configuredCandidates = Array.isArray(rankParams.candidates) ? rankParams.candidates : [];
const fallbackCandidateEmail = String(triggerCandidate.candidate_email || triggerCandidate.candidateEmail || triggerCandidate.email || '').trim();
const fallbackCandidateName = String(triggerCandidate.candidate_name || triggerCandidate.candidateName || triggerCandidate.applicant_name || triggerCandidate.applicantName || '').trim();

const baseCandidates = configuredCandidates.length ? configuredCandidates : extractedCandidates;
let normalizedCandidates = baseCandidates.map((candidate, index) => {
  if (!candidate || typeof candidate !== 'object') {
    return candidate;
  }

  if (index !== 0 || candidate.candidate_email || !fallbackCandidateEmail) {
    return candidate;
  }

  return {
    ...candidate,
    candidate_email: fallbackCandidateEmail,
    candidate_name: candidate.candidate_name || candidate.name || fallbackCandidateName || 'Candidate 1',
    metadata: {
      ...(candidate.metadata || {}),
      contact_source: 'trigger_context',
    },
  };
});

if (!normalizedCandidates.length && (fallbackCandidateEmail || fallbackCandidateName)) {
  normalizedCandidates = [{
    candidate_name: fallbackCandidateName || 'Candidate 1',
    candidate_email: fallbackCandidateEmail || null,
    resume_text: extractResult.extracted_text || '',
    skills: [],
    experience_years: null,
    metadata: {
      source: 'document_trigger',
      contact_source: 'trigger_context',
    },
  }];
}

return [{
  json: {
    request_id: String(ctx.request_id || '').replace(/^=/, ''),
    workflow_type: ctx.workflow_type || 'hr_recruitment',
    ranking_logic: rankParams.ranking_logic || 'weighted_scoring',
    criteria: rankParams.criteria || '',
    candidates: normalizedCandidates,
    extracted_text: extractResult.extracted_text || ''
  }
}];
